parameters.jsCode:
let spot1g =$('Get Digital Price').first().json.price_gram_24k ; 
let rawIBJA = $input.first().json.IBJA_Price;

// Clean the physical price just in case the website adds commas later
let physical1g = parseFloat(rawIBJA.toString().replace(/,/g, ''));

// Ensure the digital price is read as a number
spot1g = parseFloat(spot1g);

// Apply the Real-World Taxes and Fees
// Digital App: +3% GST and +3% Platform Spread
let digitalFinal = spot1g * 1.03 * 1.03;

// Physical Coin: +3% GST and +8% Making Charges
let physicalFinal = physical1g * 1.03 * 1.08;

// Calculate the Arbitrage (Difference)
let difference = physicalFinal - digitalFinal;
let cheaperOption = difference > 0 ? "Digital" : "Physical";

// Output the clean, calculated data
return {
    json: {
        Digital_1g_Final: parseFloat(digitalFinal.toFixed(2)),
        Physical_1g_Final: parseFloat(physicalFinal.toFixed(2)),
        Price_Difference_Per_Gram: parseFloat(Math.abs(difference).toFixed(2)),
        Cheaper_Option: cheaperOption
    }
};

// 1. Unpack the AI's JSON response
// (Ensure your LLM node outputs to the 'text' or 'output' property)
let aiResponse = JSON.parse($input.first().json.text || $input.first().json.output); 

// 2. Grab the original math we calculated earlier
let digitalPrice = $('Comparator').first().json.Digital_1g_Final
let physicalPrice =$('Comparator').first().json.Physical_1g_Final

// 3. Build the beautiful Telegram/WhatsApp message
let finalMessage = ` GOLD INTELLIGENCE REPORT \n\n`;
finalMessage += ` Digital (1g): ₹${digitalPrice}\n`;
finalMessage += ` Physical (1g): ₹${physicalPrice}\n`;
finalMessage += ` Arbitrage: ${aiResponse.Arbitrage_Check}\n\n`;
finalMessage += ` Market Sentiment: ${aiResponse.Sentiment}\n`;
finalMessage += ` AI Buy Score: ${aiResponse.Efficiency_Score}/100\n`;

// 4. Output everything cleanly for Google Sheets and your messaging app
return {
    json: {
        Date: new Date().toLocaleDateString('en-IN'),
        Digital_Price: digitalPrice,
        Physical_Price: physicalPrice,
        Arbitrage: aiResponse.Arbitrage_Check,
        Sentiment: aiResponse.Sentiment,
        Efficiency_Score: aiResponse.Efficiency_Score,
        Formatted_Message: finalMessage
    }
};
